fun solve(weight: Array<Long>): Long {
    val n = weight.size
    val maxWeight = arrayOf<Long>(0L)
    var currentMax = 0L

    // Precompute the maximum weight for each position
    for (i in 0 until n) {
        currentMax = maxOf(currentMax, weight[i])
        maxWeight[i] = currentMax
    }

    var result = 0L
    var i = 0

    while (i < n) {
        // Find the rightmost position where the last element is strictly less than the max in the subarray
        var j = i
        while (j < n) {
            if (weight[j] < maxWeight[j]) {
                // Check if the current subarray [i..j] is a balanced shipment
                // We can take this shipment and move i to j + 1
                result++
                i = j + 1
                break
            }
            j++
        }
        if (j == n) {
            // No more shipments can be formed
            break
        }
    }

    return result
}
